// ââ Build Daily Report + Telegram message âââââââââââââââââââââââââââââââââââââ
const vaultRaw   = $("Read 24H Signals").first().json;
const outcomeRaw = $("Read Outcomes").first().json;
const tickerRaw  = $("Fetch Price").first().json;

const memories = (vaultRaw   && vaultRaw.memories)  ? vaultRaw.memories  : [];
const outcomes = (outcomeRaw && outcomeRaw.memories) ? outcomeRaw.memories : [];
const tickerResult = tickerRaw && tickerRaw.result ? tickerRaw.result : {};
const tickerKey = Object.keys(tickerResult)[0];
const ticker = tickerResult[tickerKey] || {};
const price     = ticker.c ? parseFloat(ticker.c[0]) : 0;
const open      = ticker.o ? parseFloat(ticker.o[1]) : price;
const change24h = open > 0 ? Math.round(((price - open) / open) * 10000) / 100 : 0;

const dataOk       = price > 0;
const signalDataOk = memories.length > 0;
const outcomeDataOk = outcomes.length > 0;

// Count signals from last 24h
let buys = 0, sells = 0, waits = 0, totalConf = 0, confCount = 0;
const last24h = new Date(Date.now() - 86400000).toISOString();
for (const m of memories) {
  if (!m.created_at || m.created_at < last24h) continue;
  const c = m.content || '';
  if (/TRADE SIGNAL[^:]*:\s*BUY\s+BTC/.test(c))  buys++;
  else if (/TRADE SIGNAL[^:]*:\s*SELL\s+BTC/.test(c)) sells++;
  else if (/TRADE SIGNAL[^:]*:\s*WAIT\s+BTC/.test(c)) waits++;
  const cm = c.match(/Confidence:([\d.]+)%/);
  if (cm) { totalConf += parseFloat(cm[1]); confCount++; }
}

// Parse latest outcome report
let hitRate = 'N/A', correct = 0, incorrect = 0, gradeable = 0, avgConf = 0;
let outcomeSummary = outcomeDataOk ? 'No outcome report found' : 'Outcome data unavailable';
for (const o of outcomes) {
  const c = o.content || '';
  const hrMatch = c.match(/Hit Rate:\s*(\d+)%.*?\((\d+)\/(\d+) graded\)/);
  if (hrMatch) {
    hitRate = hrMatch[1] + '%';
    correct = parseInt(hrMatch[2]);
    gradeable = parseInt(hrMatch[3]);
    incorrect = gradeable - correct;
    const acMatch = c.match(/Avg Confidence:\s*([\d.]+)%/);
    avgConf = acMatch ? parseFloat(acMatch[1]) : 0;
    outcomeSummary = c.split('\n').slice(0, 5).join(' | ').replace(/\s+/g, ' ');
    break;
  }
}

const sessionAvgConf = confCount > 0 ? Math.round(totalConf / confCount * 10) / 10 : avgConf;
const totalSignals = buys + sells + waits;
const dateStr = new Date().toISOString().slice(0, 10);
const hitNum  = hitRate !== 'N/A' ? parseInt(hitRate) : -1;
const threshold = 55;

const statusLine = !dataOk
  ? 'PRICE DATA UNAVAILABLE'
  : !signalDataOk
  ? 'No signals recorded yet'
  : hitNum >= threshold
  ? 'Hit rate ' + hitRate + ' ABOVE ' + threshold + '% threshold'
  : hitNum >= 0
  ? 'Hit rate ' + hitRate + ' BELOW ' + threshold + '% - paper trading only'
  : 'Accumulating outcome data';

const report = 'DAILY CRYPTO REPORT - ' + dateStr +
  '\nBTC/USD: $' + Math.round(price) + ' (' + (change24h >= 0 ? '+' : '') + change24h + '% 24H)' +
  (!dataOk ? ' [PRICE FETCH FAILED]' : '') +
  '\n\nSIGNALS LAST 24H: ' + totalSignals + ' total' + (!signalDataOk ? ' [VAULT UNAVAILABLE]' : '') +
  '\nBUY: ' + buys + ' | SELL: ' + sells + ' | WAIT: ' + waits +
  '\nAvg Signal Confidence: ' + sessionAvgConf + '%' +
  '\n\nPERFORMANCE (cumulative graded):\nHit Rate: ' + hitRate + ' | Correct: ' + correct + ' | Incorrect: ' + incorrect + ' | Gradeable: ' + gradeable +
  '\n' + outcomeSummary +
  '\n\n' + statusLine;

// ââ Build Telegram Message ââââââââââââââââââââââââââââââââââââââââââââââââââââ
const HR = '\u2501'.repeat(20);
const chgEmoji = change24h > 3 ? '\uD83D\uDE80' : change24h > 0.5 ? '\uD83D\uDCC8' : change24h < -3 ? '\uD83D\uDCC9' : change24h < -0.5 ? '\uD83D\uDD34' : '\u27A1\uFE0F';
const hrBadge  = hitNum >= 70 ? '\uD83D\uDD25' : hitNum >= threshold ? '\u2705' : hitNum >= 0 ? '\u26A0\uFE0F' : '\uD83D\uDCCA';
const hrStatus = !dataOk
  ? '\uD83D\uDEA8 Price data unavailable'
  : hitNum >= threshold
  ? '\u2705 <b>Above ' + threshold + '% threshold \u2014 signal quality GOOD</b>'
  : hitNum >= 0
  ? '\u26A0\uFE0F <b>Below ' + threshold + '% \u2014 paper trading mode</b>'
  : '\uD83D\uDCCA Building dataset \u2014 need more signals';

const signalBalance = totalSignals > 0
  ? 'Bias: ' + (buys > sells + waits ? '\uD83D\uDFE2 Bullish (' + Math.round(buys/totalSignals*100) + '% BUY)' : sells > buys + waits ? '\uD83D\uDD34 Bearish (' + Math.round(sells/totalSignals*100) + '% SELL)' : '\uD83D\uDFE1 Neutral (mixed)')
  : 'No signals recorded';

const telegramMsg = [
  '\uD83D\uDDD3 <b>DAILY REPORT \u2014 CRYPTO SPECIALIST v3</b>',
  '\uD83D\uDCC5 ' + dateStr + ' \u00B7 08:00 UTC',
  '',
  HR,
  '\uD83D\uDCB0 BTC/USD: <b>$' + Math.round(price).toLocaleString('en-US') + '</b>   ' + chgEmoji + ' ' + (change24h >= 0 ? '+' : '') + change24h + '% 24H' + (!dataOk ? '  \uD83D\uDEA8 PRICE UNAVAILABLE' : ''),
  '',
  HR,
  '\uD83D\uDCCA <b>SIGNALS (last 24h): ' + totalSignals + ' total</b>' + (!signalDataOk ? '  \uD83D\uDEA8 VAULT UNAVAILABLE' : ''),
  '\uD83D\uDFE2 BUY: <b>' + buys + '</b>   \uD83D\uDD34 SELL: <b>' + sells + '</b>   \u26AA WAIT: <b>' + waits + '</b>',
  '\uD83D\uDCB3 Avg Signal Confidence: <b>' + sessionAvgConf + '%</b>',
  signalBalance,
  '',
  HR,
  hrBadge + ' <b>PERFORMANCE (cumulative)</b>',
  'Hit Rate: <b>' + hitRate + '</b>   \u2705 Correct: ' + correct + '   \u274C Incorrect: ' + incorrect + '   Graded: ' + gradeable,
  hrStatus,
  '',
  '<i>\u23F1 Next report: tomorrow 08:00 UTC  \u00B7  Threshold: ' + threshold + '%  \u00B7  v3-super</i>'
].join('\n');

return [{ json: { report, price, change24h, buys, sells, waits, hitRate, correct, incorrect, gradeable, sessionAvgConf, dateStr, dataOk, signalDataOk, outcomeDataOk, telegramMsg } }];

